// Test that cluster updates correctly replace the cluster info map entry instead of silently failing.
TEST_F(UdpProxyFilterTest, ClusterDynamicInfoMapUpdate) {
  InSequence s;

  setup(readConfig(R"EOF(
stat_prefix: foo
matcher:
  on_no_match:
    action:
      name: route
      typed_config:
        '@type': type.googleapis.com/envoy.extensions.filters.udp.udp_proxy.v3.Route
        cluster: fake_cluster
  )EOF"));

  // Create a session with the initial cluster.
  expectSessionCreate(upstream_address_);
  test_sessions_[0].expectWriteToUpstream("hello", 0, nullptr, true);
  recvDataFromDownstream("10.0.0.1:1000", "10.0.0.2:80", "hello");
  EXPECT_EQ(1, config_->stats().downstream_sess_total_.value());
  EXPECT_EQ(1, config_->stats().downstream_sess_active_.value());

  // Simulate a cluster update with a new cluster reference. This creates a new mock cluster
  // with a different object (different pointer) but the same name. The fix should replace the
  // old ClusterInfo with a new one.
  NiceMock<Upstream::MockThreadLocalCluster> updated_thread_local_cluster;
  updated_thread_local_cluster.cluster_.info_->name_ = "fake_cluster";
  // Set up the new cluster to have a different mock host.
  auto new_host_address = Network::Utility::parseInternetAddressAndPort("20.0.0.2:443");
  auto new_host = createHost(new_host_address);
  {
    Upstream::ThreadLocalClusterCommand command =
        [&updated_thread_local_cluster]() -> Upstream::ThreadLocalCluster& {
      return updated_thread_local_cluster;
    };
    cluster_update_callbacks_->onClusterAddOrUpdate("fake_cluster", command);
  }

  // The old session should still be active since it's not affected by the cluster update.
  EXPECT_EQ(1, config_->stats().downstream_sess_active_.value());

  // Create a new session with data after the cluster update. This should use the new cluster.
  EXPECT_CALL(updated_thread_local_cluster.lb_, chooseHost(_)).WillOnce(Return(new_host));
  expectSessionCreate(new_host_address);
  test_sessions_[1].expectWriteToUpstream("hello2", 0, nullptr, true);
  recvDataFromDownstream("10.0.0.1:2000", "10.0.0.2:80", "hello2");
  EXPECT_EQ(2, config_->stats().downstream_sess_total_.value());
  EXPECT_EQ(2, config_->stats().downstream_sess_active_.value());
}

